onOptionChange:
{{
  (async () => {
    const selected = q_ciudad_incoterm_dropdown.data?.find(
      x => String(x.value) === String(sl_ciudad_incoterm.selectedOptionValue)
    );

    if (selected?.source_type === "DIVISION_TERRITORIAL") {
      await BookingForm_OLD_hastaFCL.setField(
        "ciudad_incoterm_id",
        sl_ciudad_incoterm.selectedOptionValue
      );

      await BookingForm_OLD_hastaFCL.setField(
        "ubicacion_internacional_id",
        ""
      );
    } else if (selected?.source_type === "UBICACION_INTERNACIONAL") {
      await BookingForm_OLD_hastaFCL.setField(
        "ubicacion_internacional_id",
        sl_ciudad_incoterm.selectedOptionValue
      );

      await BookingForm_OLD_hastaFCL.setField(
        "ciudad_incoterm_id",
        ""
      );
    } else {
      await BookingForm_OLD_hastaFCL.setField("ciudad_incoterm_id", "");
      await BookingForm_OLD_hastaFCL.setField("ubicacion_internacional_id", "");
    }
  })()
}}

placeholderText:
{{
  ["EXW","FCA","FAS","FOB"].includes((sl_incoterm.selectedOptionLabel || "").toUpperCase())
    ? "Seleccione ciudad/lugar de origen del INCOTERM"
    : ["CFR","CIF","CPT","CIP","DAP","DPU","DDP"].includes((sl_incoterm.selectedOptionLabel || "").toUpperCase())
    ? "Seleccione ciudad/lugar de destino del INCOTERM"
    : "Seleccione primero el INCOTERM"
}}
